            if distance_matrix[current_node][node] + distance_matrix[node][destination_node] < min_distance:
                if node not in truck_nodes:
                    next_node = node
                    min_distance = distance_matrix[current_node][node] + distance_matrix[node][destination_node]

    return next_node

